import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = "Tokyo",
    temperature = 28,
    condition = "Sunny",
    humidity = 45,
    windSpeed = 8,
    unit = "C",
    forecast = [
      { day: "Mon", icon: "☀️", high: 30, low: 22 },
      { day: "Tue", icon: "⛅", high: 27, low: 20 },
      { day: "Wed", icon: "🌦️", high: 25, low: 19 },
      { day: "Thu", icon: "☁️", high: 26, low: 21 },
      { day: "Fri", icon: "☀️", high: 29, low: 22 },
    ],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="xl" style={{ maxWidth: '400px', margin: '0 auto' }}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={4} align="center">
          <Heading level={2} align="center">{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{condition}</Text>
        </Stack>

        {/* Main Temperature */}
        <Stack gap={8} align="center">
          <Text size="4xl" weight="bold">
            {temperature}°{unit}
          </Text>
        </Stack>

        {/* Details Strip */}
        <Box paddingX={16} paddingY={12} borderRadius={8} background="var(--ggui-color-neutral-100, #f3f4f6)">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
              <Text variant="label">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={8} />
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
              <Text variant="label">{windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        {/* Forecast Strip */}
        <Stack gap={16}>
          <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">5-Day Forecast</Text>
          <Stack direction="horizontal" justify="between">
            {forecast.map((item, index) => (
              <Stack key={index} align="center" gap={8}>
                <Text variant="caption" weight="medium">{item.day ?? 'N/A'}</Text>
                <Text size="xl">{item.icon ?? '🌡️'}</Text>
                <Stack align="center" gap={2}>
                  <Text variant="caption" weight="bold">{item.high ?? 0}°</Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{item.low ?? 0}°</Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}
